    "type": "inline",
    "content": "\n    (function () {\n      const LOADER_KEY = 'loaderSeen';\n      const loader = document.getElementById('loader');\n      const loaderContainer = document.querySelector('.loader-container');\n      const loaderDots = document.getElementById('loader-dots');\n      const loaderCount = document.getElementById('loader-count');\n      if (!loader || !loaderContainer || !loaderDots || !loaderCount) return;\n      let count = 0;\n      let dots = '';\n      let isPageLoaded = false;\n      let countReached100 = false;\n      let dotInterval = null;\n      const startTime = Date.now();\n      const hasSeenLoader = sessionStorage.getItem(LOADER_KEY);\n      const resetLoaderPosition = () => {\n        gsap.set(loader, { y: '0%' });\n      };\n      const updateDots = () => {\n        if (count >= 100 && isPageLoaded) {\n          loaderDots.textContent = '...';\n          return;\n        }\n        dots = dots.length < 3 ? dots + '.' : '';\n        loaderDots.textContent = dots;\n      };\n      const updateCount = () => {\n        const elapsed = (Date.now() - startTime) / 1000;\n        const minTimeReached = elapsed >= 2;\n        if (count < 100) {\n          count += Math.random() * 3;\n          if (count > 100) count = 100;\n          loaderCount.textContent = Math.floor(count);\n        }\n        if (count >= 100 && minTimeReached && isPageLoaded) {\n          if (!countReached100) {\n            countReached100 = true;\n            loaderCount.textContent = 100;\n            finishLoader();\n          }\n        } else {\n          requestAnimationFrame(updateCount);\n        }\n      };\n      const finishLoader = () => {\n        if (dotInterval) clearInterval(dotInterval);\n        gsap.to(loader, {\n          y: '-100%',\n          duration: 1.2,\n          ease: 'power3.inOut',\n          onComplete: () => {\n            gsap.set(loader, {\n              y: '0%',\n              autoAlpha: 0,\n              display: 'none',\n            });\n            loaderContainer.style.display = 'none';\n          },\n        });\n      };\n      const showLoaderFromBottom = (href) => {\n        gsap.set(loader, {\n          y: '100%',\n          autoAlpha: 1,\n          display: 'block',\n        });\n        gsap.to(loader, {\n          y: '0%',\n          duration: 0.8,\n          ease: 'power3.inOut',\n          onComplete: () => {\n            window.location.href = href;\n          },\n        });\n      };\n      document\n        .querySelectorAll('.case-link, .back-link, .case-next')\n        .forEach((link) => {\n          link.addEventListener('click', (e) => {\n            const href = link.getAttribute('href');\n            if (!href) return;\n            e.preventDefault();\n            showLoaderFromBottom(href);\n          });\n        });\n      if (!hasSeenLoader) {\n        gsap.set(loader, {\n          y: '0%',\n          autoAlpha: 1,\n          display: 'block',\n        });\n        loaderContainer.style.display = 'block';\n        dotInterval = setInterval(updateDots, 500);\n        window.addEventListener('StrucureoLoaded', () => {\n          isPageLoaded = true;\n        });\n        requestAnimationFrame(updateCount);\n        sessionStorage.setItem(LOADER_KEY, 'true');\n      } else {\n        gsap.set(loader, {\n          y: '0%',\n          autoAlpha: 0,\n          display: 'none',\n        });\n        loaderContainer.style.display = 'none';\n        window.addEventListener('StrucureoLoaded', () => {\n          gsap.set(loader, {\n            y: '0%',\n            autoAlpha: 1,\n            display: 'block',\n          });\n          gsap.to(loader, {\n            y: '-100%',\n            duration: 1.2,\n            ease: 'power3.inOut',\n            onComplete: () => {\n              gsap.set(loader, {\n                y: '0%',\n                autoAlpha: 0,\n                display: 'none',\n              });\n            },\n          });\n        });\n      }\n    })();\n\n  ",
    "isModule": false
